// Extract relevant fields from the incoming payload
const body = $input.first().json;

const event = body.event || 'unknown';
const service = body.service || body.source || 'unknown service';
const message = body.message || body.text || JSON.stringify(body).slice(0, 500);
const severity = body.severity || body.level || 'info';

return [{
  json: {
    event,
    service,
    message,
    severity,
    raw: JSON.stringify(body).slice(0, 1000)
  }
}];

const llmResponse = $input.first().json;
const summary = llmResponse.message?.content || llmResponse.response || '(no summary)';

// Pull the original event data from two nodes back
const event = $('Extract Fields').first().json;

const severityEmoji = {
  error: '🔴',
  critical: '🚨',
  warning: '🟡',
  warn: '🟡',
  info: '🔵',
  ok: '🟢'
}[event.severity?.toLowerCase()] || '⚪';

const text = `${severityEmoji} *${event.service}*\n${summary}\n\n_${new Date().toISOString().slice(0,19).replace('T',' ')} UTC_`;

return [{ json: { text } }];
